def get_max_sum(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    memo = {}
    def dp(n):
        if n in memo:
            return memo[n]
        if n == 2:
            return 2
        res = dp(n//2) + dp(n//3) + dp(n//4) + dp(n//5)
        memo[n] = max(res, n)
        return memo[n]
    return dp(n)
